import path from 'path';
import fs from 'fs';
import pino, { Logger } from 'pino';

const logger: Logger = pino({ level: 'debug' }).child({
  module: 'log-FileWriter',
});

export class FileWriter {
  private folder: string = '';
  private out: fs.WriteStream;
  private lastDay: string = '';
  private filename: string = '';

  public constructor(folder: string) {
    this.folder = folder;
    this.out = this.openStream(new Date().toISOString());
  }

  public write(data: string): void {
    // starting line looks like {"time":"1672938668808"
    const test = data.substring(2, 6);
    if (test !== 'time') {
      logger.error({ data }, 'lime not starting with time');
      throw new Error('line not starting with time');
    }
    const result = /\d+/.exec(data.substring(9, 26));
    if (!result) {
      logger.error({ data }, 'timestamp not found');
      throw new Error('timestamp not found');
    }
    const ts = result[0];
    const timestamp = new Date(parseInt(ts)).toISOString();
    if (this.out === undefined) {
      this.openStream(timestamp);
    }

    const tsDay: string = timestamp.substring(8, 10);
    if (tsDay !== this.lastDay) {
      this.openStream(timestamp);
    }

    this.out.write(data);
    this.out.write('\n');
  }

  private openStream(timestamp: string): fs.WriteStream {
    const year = timestamp.substring(0, 4);
    const month = timestamp.substring(5, 7);
    const day = timestamp.substring(8, 10);
    this.lastDay = day;
    this.filename = `${year}-${month}-${day}.txt`;

    this.out = fs.createWriteStream(path.join(this.folder, this.filename), {
      flags: 'a',
    });
    return this.out;
  }
}
import type { StreamsMessage } from '@twitch-stats/twitch';
import {
  KafkaConfig,
  KafkaConfigOpt,
  defaultValues,
  FileConfig,
  FileConfigOpt,
} from '@twitch-stats/config';
import pino, { Logger } from 'pino';
import fs from 'node:fs';
import { Kafka, Producer } from 'kafkajs';
import { ArgumentConfig, parse } from 'ts-command-line-args';
import * as readline from 'node:readline';

interface LogData {
  time: string;
  data: StreamsMessage;
}

interface ReaderConfig {
  topic: string;
  filename: string;
}

const ReaderConfigOpt: ArgumentConfig<ReaderConfig> = {
  topic: { type: String, defaultValue: defaultValues.streamsTopic },
  filename: { type: String },
};

interface Config extends ReaderConfig, KafkaConfig, FileConfig {}

const logger: Logger = pino({ level: 'debug' }).child({ module: 'log-reader' });

const config: Config = parse<Config>(
  {
    ...KafkaConfigOpt,
    ...ReaderConfigOpt,
    ...FileConfigOpt,
  },
  {
    loadFromFileArg: 'config',
  }
);

const kafka: Kafka = new Kafka({
  clientId: config.kafkaClientId,
  brokers: config.kafkaBroker,
});
logger.info({ topic: config.topic }, 'topic');
const producer: Producer = kafka.producer();
await producer.connect();

const instream: fs.ReadStream = fs.createReadStream(config.filename, {
  encoding: 'utf-8',
});

const rl: readline.Interface = readline.createInterface({
  input: instream,
  crlfDelay: Infinity,
});

for await (const line of rl) {
  const logData: LogData = JSON.parse(line) as LogData;
  if (logData.data.endConfig) {
    logData.data.endConfig.update = false;
  }
  await producer.send({
    topic: config.topic,
    messages: [
      {
        key: 'stream',
        value: JSON.stringify(logData.data),
        timestamp: logData.time,
      },
    ],
  });
}

await producer.disconnect();

