-- Convert history tables to day-partitioned tables.
-- Usage: psql -v cutover=2026-07-18 -f 001_partition_history_tables.sql
-- cutover must be a future date; the old table keeps receiving rows until then.

\set ON_ERROR_STOP on

SELECT set_config('migration.cutover', :'cutover', false);

-- The range check lets ATTACH PARTITION skip the full-table scan.
-- VALIDATE only takes SHARE UPDATE EXCLUSIVE, writers are not blocked.

-- probe ----------------------------------------------------------------------

ALTER TABLE probe ADD CONSTRAINT probe_legacy_range
  CHECK ("time" < :'cutover') NOT VALID;
ALTER TABLE probe VALIDATE CONSTRAINT probe_legacy_range;

BEGIN;
ALTER TABLE probe RENAME TO probe_legacy;
ALTER TABLE probe_legacy RENAME CONSTRAINT probe_pkey TO probe_legacy_pkey;
CREATE TABLE probe (
  stream_id bigint NOT NULL,
  user_id   bigint NOT NULL,
  viewers   integer NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  CONSTRAINT probe_pkey PRIMARY KEY (stream_id, user_id, "time")
) PARTITION BY RANGE ("time");
ALTER TABLE probe ATTACH PARTITION probe_legacy
  FOR VALUES FROM (MINVALUE) TO (:'cutover');
COMMIT;

-- stream_title ---------------------------------------------------------------

ALTER TABLE stream_title ADD CONSTRAINT stream_title_legacy_range
  CHECK ("time" < :'cutover') NOT VALID;
ALTER TABLE stream_title VALIDATE CONSTRAINT stream_title_legacy_range;

BEGIN;
ALTER TABLE stream_title RENAME TO stream_title_legacy;
ALTER TABLE stream_title_legacy RENAME CONSTRAINT stream_title_pkey TO stream_title_legacy_pkey;
CREATE TABLE stream_title (
  stream_id bigint NOT NULL,
  title     text NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  CONSTRAINT stream_title_pkey PRIMARY KEY (stream_id, title, "time")
) PARTITION BY RANGE ("time");
ALTER TABLE stream_title ATTACH PARTITION stream_title_legacy
  FOR VALUES FROM (MINVALUE) TO (:'cutover');
COMMIT;

-- stream_game ----------------------------------------------------------------

ALTER TABLE stream_game ADD CONSTRAINT stream_game_legacy_range
  CHECK ("time" < :'cutover') NOT VALID;
ALTER TABLE stream_game VALIDATE CONSTRAINT stream_game_legacy_range;

BEGIN;
ALTER TABLE stream_game RENAME TO stream_game_legacy;
ALTER TABLE stream_game_legacy RENAME CONSTRAINT stream_game_pkey TO stream_game_legacy_pkey;
CREATE TABLE stream_game (
  stream_id bigint NOT NULL,
  game_id   bigint NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  CONSTRAINT stream_game_pkey PRIMARY KEY (stream_id, game_id, "time")
) PARTITION BY RANGE ("time");
ALTER TABLE stream_game ATTACH PARTITION stream_game_legacy
  FOR VALUES FROM (MINVALUE) TO (:'cutover');
COMMIT;

-- stream_tags ----------------------------------------------------------------

ALTER TABLE stream_tags ADD CONSTRAINT stream_tags_legacy_range
  CHECK ("time" < :'cutover') NOT VALID;
ALTER TABLE stream_tags VALIDATE CONSTRAINT stream_tags_legacy_range;

BEGIN;
ALTER TABLE stream_tags RENAME TO stream_tags_legacy;
ALTER TABLE stream_tags_legacy RENAME CONSTRAINT stream_tags_pkey1 TO stream_tags_legacy_pkey;
CREATE TABLE stream_tags (
  stream_id bigint NOT NULL,
  tag       text[] NOT NULL,
  "time"    timestamptz(6) NOT NULL,
  CONSTRAINT stream_tags_pkey1 PRIMARY KEY (stream_id, tag, "time")
) PARTITION BY RANGE ("time");
ALTER TABLE stream_tags ATTACH PARTITION stream_tags_legacy
  FOR VALUES FROM (MINVALUE) TO (:'cutover');
COMMIT;

-- daily partitions for the first week after cutover --------------------------

DO $$
DECLARE
  tbl text;
  day date;
  cutover date := current_setting('migration.cutover')::date;
BEGIN
  FOREACH tbl IN ARRAY ARRAY['probe', 'stream_title', 'stream_game', 'stream_tags'] LOOP
    FOR i IN 0..6 LOOP
      day := cutover + i;
      EXECUTE format(
        'CREATE TABLE IF NOT EXISTS %I PARTITION OF %I FOR VALUES FROM (%L) TO (%L)',
        tbl || '_p' || to_char(day, 'YYYYMMDD'), tbl, day, day + 1
      );
    END LOOP;
  END LOOP;
END $$;

